<?php require_once __DIR__.'/../includes/db.php'; require_once __DIR__.'/../includes/functions.php'; if(!empty($_SESSION['admin_id'])) redirect('dashboard.php'); $error=''; if($_SERVER['REQUEST_METHOD']==='POST'){ if(!verify_csrf($_POST['csrf_token']??null)){ $error='Invalid security token.'; } else { $u=post_value('username'); $p=post_value('password'); $st=db()->prepare("SELECT * FROM admins WHERE username=? AND status='active' LIMIT 1"); $st->execute([$u]); $admin=$st->fetch(); if($admin && password_verify($p,$admin['password_hash'])){ $_SESSION['admin_id']=$admin['id']; $_SESSION['admin_name']=$admin['name']; redirect('dashboard.php'); } $error='Invalid username or password.'; }} ?><!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><script src="https://cdn.tailwindcss.com"></script><title>Admin Login</title></head><body class="grid min-h-screen place-items-center bg-slate-950"><form method="post" class="w-full max-w-md rounded-2xl bg-white p-8 shadow"><h1 class="mb-6 text-3xl font-black text-slate-950">Admin Login</h1><?php if($error):?><p class="mb-4 rounded bg-red-100 p-3 text-red-700"><?=e($error)?></p><?php endif;?><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input name="username" required class="mb-3 w-full rounded border p-3" placeholder="Username"><input type="password" name="password" required class="mb-5 w-full rounded border p-3" placeholder="Password"><button class="w-full rounded bg-slate-950 p-3 font-bold text-white">Login</button></form></body></html>
